enum Shape {
    Circle(f64),
    Square(f64),
}
impl std::fmt::Display for Shape {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        match self {
            Shape::Circle(r) => write!(f, "Circle(r={r})"),
            Shape::Square(s) => write!(f, "Square(s={s})"),
        }
    }
}

